import { Search } from "lucide-react"

interface Props {
  employees: any[]
  search: string
  setSearch: any
  filterRole: string
  setFilterRole: any
}

export default function EmployeeTable({
  employees,
  search,
  setSearch,
  filterRole,
  setFilterRole,
}: Props) {

  const filteredEmployees =
    employees.filter(
      (employee: any) => {

        const matchSearch =
          employee.name
            .toLowerCase()
            .includes(
              search.toLowerCase()
            ) ||
          employee.email
            .toLowerCase()
            .includes(
              search.toLowerCase()
            )

        const matchRole =
          filterRole === "all" ||
          employee.role ===
            filterRole

        return (
          matchSearch &&
          matchRole
        )
      }
    )

  return (
    <div className="card p-8 mb-10">

      {/* HEADER */}
      <div className="flex items-center justify-between mb-6">

        <h2 className="text-2xl font-bold text-red-700">
          Employees
        </h2>

        <div className="flex gap-4">

          {/* SEARCH */}
          <div className="relative">

            <Search
              size={18}
              className="absolute left-4 top-4 text-gray-400"
            />

            <input
              placeholder="Search..."
              value={search}
              onChange={(e) =>
                setSearch(
                  e.target.value
                )
              }
              className="input pl-11"
            />

          </div>

          {/* FILTER */}
          <select
            value={filterRole}
            onChange={(e) =>
              setFilterRole(
                e.target.value
              )
            }
            className="input"
          >

            <option value="all">
              All
            </option>

            <option value="employee">
              Employee
            </option>

            <option value="hr">
              HR
            </option>

            <option value="admin">
              Admin
            </option>

          </select>

        </div>

      </div>

      {/* TABLE */}
      <div className="table-container">

        <table className="w-full">

          <thead className="table-head">

            <tr>

              <th className="text-left p-4">
                Name
              </th>

              <th className="text-left p-4">
                Email
              </th>

              <th className="text-left p-4">
                Role
              </th>

            </tr>

          </thead>

          <tbody>

            {filteredEmployees.map(
              (employee: any) => (

                <tr
                  key={employee.id}
                  className="table-row"
                >

                  <td className="p-4 font-medium">
                    {employee.name}
                  </td>

                  <td className="p-4">
                    {employee.email}
                  </td>

                  <td className="p-4">

                    <span
                      className={`px-4 py-2 rounded-full text-sm font-semibold ${
                        employee.role ===
                        "admin"
                          ? "bg-red-100 text-red-700"
                          : employee.role ===
                            "hr"
                          ? "bg-yellow-100 text-yellow-700"
                          : "bg-gray-100 text-gray-700"
                      }`}
                    >

                      {employee.role}

                    </span>

                  </td>

                </tr>

              )
            )}

          </tbody>

        </table>

      </div>

    </div>
  )
}